const founder = String($json.founder_status || '').toUpperCase();
if (founder !== 'APPROVED') {
  throw new Error('Refusing send: founder_status is not APPROVED');
}

return [{
  json: {
    ...$json,
    status: 'APPROVED'
  }
}];

